args.sparql:
SELECT ?attendance
WHERE {
  ?competition wdt:P31 wd:Q54721 .
  ?competition wdt:P585 ?date .
  FILTER (SUBSTR(STR(?date), 1, 4) IN ('1977', '1978', '2008', '2009'))

  ?game wdt:P154 ?competition .

  { ?game wdt:P1080 wd:Q160889 ; wdt:P1081 wd:Q160908 }
  UNION
  { ?game wdt:P1080 wd:Q160908 ; wdt:P1081 wd:Q160889 }

  ?game wdt:P1092 ?attendance
}
ORDER BY ASC(?attendance)
LIMIT 1 OFFSET 2

SELECT ?attendance
WHERE {
  ?competition wdt:P31 wd:Q192550 .
  ?competition wdt:P585 ?date .
  FILTER (SUBSTR(STR(?date), 1, 4) IN ('1977', '1978', '2008', '2009'))

  ?game wdt:P154 ?competition .
  {
    ?game wdt:P1080 wd:Q160889 .
    ?game wdt:P1081 wd:Q160908 .
    ?game wdt:P1092 ?attendance .
  }
  UNION
  {
    ?game wdt:P1080 wd:Q160908 .
    ?game wdt:P1081 wd:Q160889 .
    ?game wdt:P1092 ?attendance .
  }
}
ORDER BY ASC(?attendance)
LIMIT 1 OFFSET 2

SELECT ?attendance WHERE {
  ?competition wdt:P31 wd:Q192550 ;
              wdt:P585 ?date .
  FILTER (SUBSTR(STR(?date), 1, 4) IN ('1977', '1978', '2008', '2009'))
  ?game wdt:P154 ?competition .
  ?game wdt:P1080 ?homeTeam ;
        wdt:P1081 ?awayTeam .
  FILTER ( ( ?homeTeam = wd:Q160889 && ?awayTeam = wd:Q160908 ) ||
           ( ?homeTeam = wd:Q160908 && ?awayTeam = wd:Q160889 ) )
  ?game wdt:P1075 ?attendance .
}
ORDER BY ASC(?attendance)
LIMIT 1 OFFSET 2
